import{_ as e,o as d,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Page Settings","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Page/page-settings.md","filePath":"fa/Page/page-settings.md","lastUpdated":1781962217000}'),o={name:"fa/Page/page-settings.md"};function n(i,t,l,g,s,c){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="page-settings" tabindex="-1">Page Settings <a class="header-anchor" href="#page-settings" aria-label="Permalink to &quot;Page Settings&quot;">​</a></h1><p>Page settings نمایش site، defaults مربوط به upload page، background images و ظاهر admin panel را کنترل می‌کند.</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Site title</td><td>title نمایش‌داده‌شده در browser tab.</td></tr><tr><td>Site icon</td><td>icon کوچک نمایش‌داده‌شده در browser tab.</td></tr><tr><td>ImgBed name</td><td>نام نمایش‌داده‌شده در frontend pages.</td></tr><tr><td>ImgBed logo</td><td>logo image نمایش‌داده‌شده در frontend pages.</td></tr><tr><td>Logo link</td><td>URLی که با click روی logo یا avatar باز می‌شود.</td></tr><tr><td>Background switch interval</td><td>interval چرخش برای چند background، بر حسب milliseconds. <code>60000</code> یعنی 60 seconds.</td></tr><tr><td>Background opacity</td><td>opacity مربوط به background image از <code>0</code> تا <code>1</code>. مقدار کمتر تصویر را روشن‌تر می‌کند.</td></tr><tr><td>Default URL prefix</td><td>prefix استفاده‌شده هنگام ساخت image links. خالی باشد، current site domain استفاده می‌شود.</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Announcement</td><td>announcement نمایش‌داده‌شده بالای upload page. HTML پشتیبانی می‌شود.</td></tr><tr><td>Default upload channel</td><td>upload channel پیش‌فرض در upload page. می‌توانید Smart Dispatch هم انتخاب کنید.</td></tr><tr><td>Default upload directory</td><td>default upload directory، مثل <code>/user/</code>. خالی یا <code>/</code> یعنی root.</td></tr><tr><td>Default naming method</td><td>استراتژی پیش‌فرض ساخت filename بعد از upload. پایین‌تر توضیح داده شده.</td></tr><tr><td>Convert to WebP by default</td><td>images را پیش از upload به WebP تبدیل می‌کند.</td></tr><tr><td>Enable compression by default</td><td>images را پیش از upload در browser به‌صورت local compress می‌کند.</td></tr><tr><td>Default compression threshold</td><td>وقتی image از این size بزرگ‌تر باشد، خودکار compress می‌شود، بر حسب MB.</td></tr><tr><td>Default target size</td><td>target file size پس از compression، بر حسب MB.</td></tr><tr><td>Login page background</td><td>background image برای user login page.</td></tr><tr><td>Upload page background</td><td>background image برای upload page.</td></tr><tr><td>Footer portal link</td><td>URLی که footer portal button باز می‌کند.</td></tr><tr><td>Hide footer</td><td>اگر enabled باشد، frontend footer را پنهان می‌کند.</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Admin login background</td><td>background image برای admin login page.</td></tr><tr><td>Admin background</td><td>background image برای admin pages. یک image URL یا چند URL.</td></tr><tr><td>Image loading mode</td><td>preview loading mode برای admin file list. Original، original images را load می‌کند. Smart loading برای public images، thumbnails را و برای restricted images، originals را ترجیح می‌دهد.</td></tr><tr><td>Thumbnail source</td><td>service ساخت thumbnails: wsrv.nl، Cloudflare Image Resizing یا WordPress Photon. Cloudflare Image Resizing باید پیش از انتخاب، در Cloudflare enabled باشد.</td></tr><tr><td>Live2D widget</td><td>یک Live2D character در admin panel نشان می‌دهد.</td></tr><tr><td>Firework click effect</td><td>هنگام click روی page، firework effect نشان می‌دهد.</td></tr><tr><td>Star cursor trail</td><td>هنگام حرکت mouse، star trail نشان می‌دهد.</td></tr></tbody></table><h2 id="background-image-formats" tabindex="-1">Background Image Formats <a class="header-anchor" href="#background-image-formats" aria-label="Permalink to &quot;Background Image Formats&quot;">​</a></h2><p>Login page background، upload page background و admin login background این formats را پشتیبانی می‌کنند:</p><table tabindex="0"><thead><tr><th>Value</th><th>Effect</th></tr></thead><tbody><tr><td><code>bing</code></td><td>از Bing wallpaper rotation استفاده می‌کند.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>چند image را rotate می‌کند.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>یک background image استفاده می‌کند.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>از random image API link استفاده می‌کند. می‌توانید Random Image API خودتان را در Other Settings configure کنید و generated random image link را اینجا به‌عنوان single-background entry paste کنید.</td></tr></tbody></table><p>admin background از image URLs پشتیبانی می‌کند. چند URL را طبق prompt صفحه می‌توان با comma انگلیسی جدا کرد. خالی باشد، default background استفاده می‌شود.</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>time-random prefix + original filename، مثل <code>1760000000000_cat.png</code>.</td></tr><tr><td>Prefix only</td><td>فقط time-random prefix و extension، مثل <code>1760000000000.png</code>.</td></tr><tr><td>Original name only</td><td>original filename را نگه می‌دارد، مثل <code>cat.png</code>. اگر duplicate باشد، ImgBed <code>(1)</code>، <code>(2)</code> و مانند آن اضافه می‌کند.</td></tr><tr><td>Short link</td><td>از 8-character short ID و extension استفاده می‌کند، مثل <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const p=e(o,[["render",n]]);export{u as __pageData,p as default};
